INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('d2633f61-a76e-5df4-b116-27a7f2a87595', '0461f5ca-d18d-43d7-bcea-32029302a3d7', 'It is ___ to expect a professional athlete to perform at a high level without any training or preparation.', '如果期望一位專業運動員在沒有任何訓練或準備的情況下表現出色，那是很荒謬的。', 'absurd', 'common', 'possible', 'normal', 'ab (離開/偏離) + surdus (聾的) → 引申為「不合情理的」或「荒謬的」。', '想像一個人在講道理，對方卻像「聾了一樣」(surdus) 完全聽不進去，這種情況非常「荒謬」(absurd)。', '2026-07-06 16:18:50', '2026-07-06 16:18:50'),
('28979c96-9d81-57da-90d4-c0742c63a60d', '13b69b65-2402-453c-99f3-94cadddc84ee', 'After reviewing the company''s financial records, the ___ advised the CEO to adjust the annual budget.', '在審查公司的財務紀錄後，那位會計師建議執行長調整年度預算。', 'accountant', 'architect', 'pilot', 'surgeon', 'account (帳目/計算) + -ant (表示人的字尾)', 'account (帳目) + ant (人) → 負責計算帳目的人 → 會計師', '2026-07-06 16:56:53', '2026-07-06 16:56:53'),
('5cd00270-0adf-5d83-8722-5709c878bde5', 'eeeb53ad-cb73-451e-8c76-7d714c1f578e', 'Please write your home ___ on this form.', '請在這張表格上寫下你的住家地址。', 'address', 'name', 'age', 'color', 'ad- (向/往) + dress (排列/裝扮) → 引申為「寫上地址」或「向某人致詞」。', '寫下 address (地址) 才能讓信件找到正確的方向。', '2026-07-06 13:13:03', '2026-07-06 13:13:03'),
('569963bb-8aa7-52dd-95aa-258a751fa171', '838b6b67-0249-4700-8486-54ba8e32ef72', 'I saw an interesting ___ for a new toy on TV.', '我在電視上看到一個新玩具的有趣廣告。', 'advertisement', 'dictionary', 'magazine', 'newspaper', 'ad (向) + vert (轉) + ment (名詞字尾) → 轉向大家的注意力 → 廣告', '把注意力 (vert) 轉向 (ad) 某個產品，就是做廣告。', '2026-07-06 13:15:21', '2026-07-06 13:15:21'),
('d972ad7a-8e16-5bde-bc76-ad7dc0b8d931', '394cf2dd-d137-4a5c-8f02-329a749abada', 'The company spent a large amount of money on a creative ___ to attract more young customers.', '這間公司花了大筆資金製作一個有創意的廣告，以吸引更多年輕顧客。', 'advertisement', 'achievement', 'appointment', 'argument', 'ad- (朝向) + vert (轉) + -ise (動詞化) + -ment (名詞字尾) → 意指轉向大眾的訊息，即廣告。', '想像把產品的注意力 (advert) 轉向 (vert) 消費者，最後加上 -ment 變成名詞。', '2026-07-06 18:12:45', '2026-07-06 18:12:45'),
('2520ca89-4eca-5c7d-9a96-7db2971bfdf1', 'c63ac307-a41a-46d2-9fea-02a7a182eafc', 'The rapid advancement of ___ has sparked intense debates about the ethics of machine autonomy.', '___ 的快速進步，引發了關於機器自主權倫理的激烈辯論。', 'artificial intelligence', 'renewable energy', 'social media', 'space exploration', 'artificial (人造的) + intelligence (智慧) → 人工智慧', '將 artificial (人造的) 與 intelligence (智慧) 結合，即可記住「人工智慧」。', '2026-07-07 00:32:23', '2026-07-07 00:32:23'),
('f2361205-23c0-5105-aee2-1e12fafbaa5d', '048d74fe-0071-4a5c-bb88-adbb1dc40b8b', 'The teacher decided to ___ a different research topic to each student in the class.', '老師決定為班上的每位學生分配不同的研究主題。', 'assign', 'suggest', 'describe', 'present', 'assign 的字根由 as- (towards/to) 與 sign (mark/seal) 組成，原意為「做出標記」，引申為「指派、分配」。', '想像在任務上面「簽名」(sign) 標記，就是「指派」(assign) 任務。', '2026-07-07 01:18:17', '2026-07-07 01:18:17'),
('ebbbe885-9c9b-538a-8ff6-59c390b5e3b9', 'd67b4316-d059-4eb4-9168-c5327ac0231f', 'We had a great ___ at the beach last weekend.', '我們上週末在海邊辦了一場很棒的烤肉。', 'barbecue', 'meeting', 'lesson', 'exam', '(n.) 烤肉 (v.) 烤，炙(肉類)', '看到 BBQ (Barbecue 的縮寫) 就想到烤肉！', '2026-07-07 02:21:25', '2026-07-07 02:21:25'),
('f8c2627b-0618-5975-a160-7dc2af0d9ead', 'd8b3ec22-92b0-4e3d-bb59-a2558ec8f82c', 'I feel very sick, so I must see a ___ today.', '我感覺很不舒服，所以我今天必須去看醫生。', 'doctor', 'teacher', 'farmer', 'singer', 'doc- 來自拉丁文，意思是教導或學習。', 'doctor 唸起來像多考，醫生需要通過很多考試。', '2026-07-07 04:57:00', '2026-07-07 04:57:00'),
('84a69465-ab70-5724-bdf7-a9f92eb09dc1', '28da0acf-250b-4dd3-a479-f5081a241c88', 'Students usually graduate from ___ before they enter junior high school.', '學生通常在進入國中之前，會先從小學畢業。', 'elementary school', 'college', 'museum', 'zoo', 'element (基本、元素) + ary (形容詞字尾) → 基本的 + school (學校)。', 'elementary 代表最基礎的，小學是學習最基礎知識的地方。', '2026-07-07 03:36:36', '2026-07-07 03:36:36'),
('c904f322-0f97-59d4-91ac-8c9c4e5c82c5', '985986ba-ca2d-4ee4-9439-4abea496bb20', 'She ___ swimming in the pool.', '她很喜歡在泳池裡游泳。', 'enjoys', 'hates', 'sings', 'cooks', 'en- (使) + joy (快樂) → 享受', 'en- 是「使...」的前綴，joy 是「快樂」，使自己快樂就是「享受」。', '2026-07-07 03:56:48', '2026-07-07 03:56:48'),
('0dd0e229-db45-570e-9515-5603be345ab5', '50d82567-b36d-40c2-a180-9cbe53f57d02', 'The players are ready for the ___.', '球員們為決賽做好了準備。', 'final', 'party', 'lesson', 'song', 'fin 表示 結束 (end)', '比賽到最後階段就是 final (決賽)', '2026-07-07 11:54:45', '2026-07-07 11:54:45'),
('9f8af2b7-3160-5782-a553-0593ede85745', '4c7bf4a2-cdaa-4597-b8ab-ccf11ab3e97a', 'We have lived in Taipei ___ five years.', '我們在台北已經住了五年。', 'for', 'since', 'during', 'in', '介係詞，表示一段時間', 'for + 一段時間', '2026-07-05 08:40:54', '2026-07-05 08:40:54'),
('21796aa2-3577-5d14-832c-cc417b821f09', 'ff85934d-b8c5-40bb-9a09-bb0432a50db6', 'The teacher will ___ the students into four teams.', '老師會把學生分成四個小組。', 'group', 'move', 'lead', 'send', 'group 為動詞，表示「將...分組」。', '想像大家 group 在一起，形成一個小圈圈。', '2026-07-08 06:31:29', '2026-07-08 06:31:29'),
('a31c84de-d7b7-5ca3-aaca-b1da867a2461', '546e2495-ca58-4736-affc-a515cf7ecf0d', 'I like to put ___ in my tea to make it sweet.', '我喜歡在茶裡加點蜂蜜來讓它變甜。', 'honey', 'salt', 'pepper', 'butter', 'honey 是名詞，意指蜜蜂產出的甜味物質。', 'Honey 讀音接近「哈妮」，可以聯想對心愛的「哈妮」說甜言蜜語，或送她蜂蜜。', '2026-07-08 07:57:25', '2026-07-08 07:57:25'),
('d4dd5c5b-5175-56cc-b726-99a8b56f0989', '4f5081e4-8d5a-4e56-8dfc-7cbff02e7004', 'The cowboy rides a ___ every day.', '這位牛仔每天都騎著馬。', 'horse', 'cow', 'duck', 'pig', 'horse 為單字本身，意為「馬」。', '想像西部牛仔騎著 horse 在荒野奔馳的畫面。', '2026-07-08 08:03:53', '2026-07-08 08:03:53'),
('5466e575-4edc-53d6-9ede-df0b747a6abd', '825a281c-8ba8-4992-9d3c-d724865fa454', 'The movie is not that scary.', '這部電影沒那麼恐怖。', 'that', 'always', 'never', 'often', '副詞，用來表示程度，意為『那麼』。', '表示程度的那麼。', '2026-07-05 13:26:49', '2026-07-05 13:26:49');
